# Scoring framework calculation — illustrative Python
# Dimensions: business_value, feasibility, strategic_fit, risk_data
# Each scored 1–5 by a review panel; weights sum to 1.0

WEIGHTS = {
    "business_value": 0.30,
    "feasibility": 0.25,
    "strategic_fit": 0.25,
    "risk_data": 0.20,
}
MAX_SCORE_PER_DIM = 5  # 1-to-5 scale

def compute_composite_score(panel_scores: dict[str, int]) -> float:
    """
    Returns a normalised score in [0, 100].
    panel_scores: {dimension: score_1_to_5}
    """
    weighted_sum = sum(
        panel_scores[dim] * weight
        for dim, weight in WEIGHTS.items()
    )
    max_possible = MAX_SCORE_PER_DIM * sum(WEIGHTS.values())  # = 5.0
    return round((weighted_sum / max_possible) * 100, 1)

def classify_band(score: float) -> str:
    if score >= 70:
        return "GREEN — advance to pipeline"
    elif score >= 40:
        return "AMBER — review and park"
    else:
        return "RED — decline"

# Example: customer support triage agent
panel_scores = {
    "business_value": 4,   # clear cost savings in FTE hours
    "feasibility": 3,      # data exists but needs cleansing
    "strategic_fit": 5,    # directly maps to CX transformation OKR
    "risk_data": 3,        # moderate data quality risk
}
score = compute_composite_score(panel_scores)
print(f"Composite score: {score}")   # 75.0
print(classify_band(score))           # GREEN — advance to pipeline
